parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    let parsed;
    try {
      const text = item.json.content[0].text;
      parsed = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      if (match) {
        parsed = JSON.parse(match[0]);
      } else {
        parsed = {
          variants: [
            {variant_name:'Variant A', headline:'Headline A', description:'Description A', cta:'Learn More', key_difference:'Focuses on value'},
            {variant_name:'Variant B', headline:'Headline B', description:'Description B', cta:'Get Started', key_difference:'Focuses on urgency'},
            {variant_name:'Variant C', headline:'Headline C', description:'Description C', cta:'Try Free', key_difference:'Focuses on risk-free'}
          ]
        };
      }
    }
    const campaign = $node['Split In Batches'].json;
    results.push({json: {
      campaign_id: campaign.id,
      campaign_name: campaign.campaign_name,
      business_id: campaign.business_id,
      business_email: campaign.business_email || '',
      variants: parsed.variants || [],
      created_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message}}];
}
